SELECT m.music_id, m.name, m.owner, m.comment, m.mark
FROM music_info m, user_music_relation_info r
WHERE m.music_id=r.music_id AND r.user_id=#{userId}
LIMIT #{start}, #{limit};

SELECT m.music_id, m.name, m.owner, m.comment, m.mark
FROM music_info m, user_music_relation_info r
WHERE m.name LIKE CONCAT('%', #{keywords},'%') AND
      m.music_id = r.music_id AND
      r.user_id = #{userId}
LIMIT #{start}, #{limit};
